mapper.select:
SELECT h.HIS_ID as historyId, h.CONTRACT_NO as contractNo, c.CONTRACT_YEAR as contractYear, c.SUB_CD as subCd, s.SW_NM as swName, cust.COMPANY_NM as customerCompanyNm, cust.DEPARTMENT_NM as customerDepartmentNm, cust.MANAGE_NM as customerManageNm, c.DEPT_CD as customerDeptCd, part.COMPANY_NM as partnerCompanyNm, p.COMP_CD as partnerDeptCd, h.HIS_SEQ as historySeq, h.HIS_TYPE_CD as historyTypeCd, h.HIS_CONTENTS as historyContents FROM TS_MA_HISTORY h INNER JOIN TS_WORK_SW_CONTRACT c ON h.CONTRACT_NO = c.CONTRACT_NO INNER JOIN TS_WORK_SW_PARTNER p ON c.SUB_CD = p.SUB_CD INNER JOIN TS_WORK_SW s ON p.SW_CD = s.SW_CD LEFT JOIN V_ORGANIZATION_STRUCTURE cust ON c.DEPT_CD = cust.ORIGIN_CD LEFT JOIN V_ORGANIZATION_STRUCTURE part ON p.COMP_CD = part.ORIGIN_CD WHERE h.USE_YN = 'Y'
AND c.CONTRACT_YEAR = #{contractYear}
AND cust.COMPANY_CD = #{customer}
AND cust.MANAGE_CD = #{department}
AND part.COMPANY_CD = #{partner}
AND s.SW_NM LIKE CONCAT('%', #{swName}, '%')
ORDER BY ${sortBy}
ORDER BY h.REG_DT DESC
LIMIT #{pageSize} OFFSET #{offset}

SELECT COUNT(*)
FROM TS_MA_HISTORY h
INNER JOIN TS_WORK_SW_CONTRACT c ON h.CONTRACT_NO = c.CONTRACT_NO
INNER JOIN TS_WORK_SW_PARTNER p ON c.SUB_CD = p.SUB_CD
INNER JOIN TS_WORK_SW s ON p.SW_CD = s.SW_CD
LEFT JOIN V_ORGANIZATION_STRUCTURE cust ON c.DEPT_CD = cust.ORIGIN_CD
LEFT JOIN V_ORGANIZATION_STRUCTURE part ON p.COMP_CD = part.ORIGIN_CD
WHERE h.USE_YN = 'Y'

    AND c.CONTRACT_YEAR = #{contractYear}


    AND cust.COMPANY_CD = #{customer}


    AND cust.MANAGE_CD = #{department}


    AND part.COMPANY_CD = #{partner}


    AND s.SW_NM LIKE CONCAT('%', #{swName}, '%')
